@startuml
skinparam classAttributeIconSize 0

class Observer {
    + notify(event: ManagerEvent)
}

interface System <<C>> {
    - managedTypes: List<ComponentType>
    - filteredEntities: List<Entity>

    + addEntityRef(): Unit
    + removeEntityRef(): Unit
    + update(): Unit

    # checkEntityIsCompatible(): Unit
}

note "Module + Case Class" as N1

abstract Entity <<Product Type,C>> {
    = ID : Int
    ~ components : Map<ComponentType, Component>
}

enum ComponentType <<E>> {
DIRECTION, POSITION,SPEED, SPAWN,... }


Component <|-- EntityType 
EntityType --|> Module 

System --> "*" ManagedClass  
ManagedClass ..* "**" FilteredClasses  

FilteredClasses o--o "*..*" ComponentsMap 


@enduml
